-- Authors with open-ended birth year (no death year), born before 1880 → public domain
-- These are people born before 1880 who almost certainly died before 1956
UPDATE books SET copyrightProtectedUntil = 0
WHERE copyrightProtectedUntil IS NULL
AND authors REGEXP '^[^;]+, [0-9]{3,4}-([^0-9]|$)'
AND CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(authors, ', ', -1), '-', 1) AS UNSIGNED) < 1880
AND CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(authors, ', ', -1), '-', 1) AS UNSIGNED) > 0;

SELECT COUNT(*) as total_public_domain FROM books WHERE copyrightProtectedUntil = 0;
SELECT COUNT(*) as total_protected FROM books WHERE copyrightProtectedUntil > 0;
SELECT COUNT(*) as total_no_override FROM books WHERE copyrightProtectedUntil IS NULL;

